            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/announcements"]""",
            Tags = """["announcements","admin","reference"]""",
            ContentJson = """{"title":"Announcements Admin Field Reference","groups":[{"heading":"Panel Tabs","items":[{"label":"Announcements","value":"The tab you start on. Lists every announcement you have sent and holds the New Announcement button."},{"label":"Templates","value":"Reusable announcement drafts. Holds the New Template button. Pick a template to fill in the send form."}]},{"heading":"Sent Announcements List — Columns","items":[{"label":"Title","value":"The announcement headline. Click to sort."},{"label":"Severity","value":"How urgent it is, shown as a colored label: Critical (red), Warning (amber), Info (blue). Sort or filter by it."},{"label":"Scope","value":"Who it went to: everyone, selected teams, one team, or team leads only. Click to sort."},{"label":"Sent By","value":"The admin or manager who sent the announcement. Click to sort."},{"label":"Sent","value":"When it was sent, shown as date and time. Click to sort."},{"label":"Acks","value":"How many people have confirmed it. Click to sort."},{"label":"Actions","value":"An eye icon that opens the list of who confirmed. Clicking the row does the same."}]},{"heading":"Send Announcement Window — Fields","items":[{"label":"Template","value":"Optional. Pick a saved template to fill in the message, urgency, audience, and confirm setting. You can still edit everything afterward. Choose '-- None --' to start blank."},{"label":"Title (required)","value":"The headline people see. Up to 200 characters."},{"label":"Content (required)","value":"The body of the message. Up to 5,000 characters."},{"label":"Severity (required)","value":"How urgent it is: Info, Warning, or Critical. Starts on Info. Sets the label color and signals urgency; it does not change who gets it."},{"label":"Scope (required)","value":"Who gets it: everyone, selected teams, one team, or team leads only. Starts on everyone."},{"label":"Target Teams","value":"Shown only when you send to selected teams or one team. Pick which team or teams should get it."},{"label":"Expires At","value":"Optional. After this date the announcement stops showing; the record and its confirmations stay. Leave blank for no expiry."},{"label":"Require Acknowledgment","value":"An on/off switch. When on, people must confirm they saw it, and you can see who did."},{"label":"Send button","value":"Delivers the announcement right away. Stays disabled until you fill in a title and message."}]},{"heading":"Scope Options","items":[{"label":"Company-Wide","value":"Everyone in the company. No team to pick."},{"label":"Selected Teams","value":"Members of one or more teams you choose."},{"label":"Individual Team","value":"A single team you choose."},{"label":"Team Leads Only","value":"Only managers and admins across the whole company, not every member. There is no team to pick."}]},{"heading":"Severity Levels","items":[{"label":"Info","value":"Blue label. Routine notices. The starting choice."},{"label":"Warning","value":"Amber label. Important but not urgent."},{"label":"Critical","value":"Red label. Urgent; usually paired with requiring people to confirm."}]},{"heading":"Who-Confirmed List","items":[{"label":"Header count","value":"How many people have confirmed the announcement."},{"label":"Confirmation-required note","value":"Shown when the announcement asked people to confirm."},{"label":"The list","value":"Each person who confirmed, with their name and when they confirmed."},{"label":"Empty state","value":"'No acknowledgments yet' when no one has confirmed."},{"label":"Close","value":"Closes the window."}]},{"heading":"Template Fields (New Template Window)","items":[{"label":"Name (required)","value":"How the template appears in the Templates list and the template picker. Up to 200 characters."},{"label":"Content (required)","value":"The default message the template fills in. Up to 5,000 characters."},{"label":"Default Severity (required)","value":"The urgency the template starts with: Info, Warning, or Critical."},{"label":"Default Scope (required)","value":"The audience the template starts with: everyone, selected teams, one team, or team leads only."},{"label":"Require Acknowledgment by Default","value":"An on/off switch for whether this template asks people to confirm."},{"label":"Create Template button","value":"Saves the template. Stays disabled until you fill in a name and message."}]},{"heading":"Templates List — Columns","items":[{"label":"Name","value":"The template name. Click to sort."},{"label":"Severity","value":"The template's default urgency. Click to sort."},{"label":"Scope","value":"The template's default audience. Click to sort."},{"label":"Ack Required","value":"Shows 'Yes' or 'No' — whether this template asks people to confirm. Click to sort."},{"label":"Actions","value":"A trash icon that deletes the template after you confirm. Does not affect announcements already sent."}]},{"heading":"Roles & Permissions","items":[{"label":"Send an announcement","value":"Admins and Managers."},{"label":"View the sent list & who confirmed","value":"Admins and Managers."},{"label":"Create or delete a template","value":"Admins only."},{"label":"Receive / confirm announcements","value":"Anyone the announcement was sent to."}]},{"heading":"Validation Rules","items":[{"label":"Title","value":"Required. Up to 200 characters."},{"label":"Content","value":"Required. Up to 5,000 characters."},{"label":"Severity","value":"Required. Info, Warning, or Critical."},{"label":"Scope","value":"Required. One of the four audience choices."},{"label":"Target Teams","value":"Required when you send to selected teams or one team, so the announcement has a clear audience."},{"label":"Template Name / Content","value":"Both required. Up to 200 and 5,000 characters."}]},{"heading":"Real-Time Behavior","items":[{"label":"Instant delivery","value":"A sent announcement reaches its audience right away and pops up as a banner."},{"label":"Live list updates","value":"New announcements appear at the top of the list on their own, including ones a colleague sends while you are looking."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Announcements Admin Knowledge Check",
            Slug = "announcements-admin-quiz",
            Summary = "Test your knowledge of the Admin > Announcements panel: sending an announcement, scope and severity, the acknowledgment roster, and templates.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/announcements"]""",
            Tags = """["announcements","admin","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":7,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ann1","text":"Where do you compose and manage company announcements?","options":[{"id":"a","text":"In the Chat panel — type the message in any channel and mark it as an announcement"},{"id":"b","text":"In Admin → Announcements, which has an Announcements tab and a Templates tab","isCorrect":true},{"id":"c","text":"In Notifications → Preferences"},{"id":"d","text":"On the Dashboard, via the Announcements widget"}],"explanation":"Announcements are composed and managed in the Admin > Announcements panel (route /admin/announcements). It has two tabs — Announcements (the sent list + New Announcement) and Templates. The Chat broadcast channel surfaces announcements, but you author and manage them here, not in Chat."},{"id":"ann2","text":"You want a Critical safety notice to go only to the company's team leads (managers), not to every employee. What Scope do you choose?","options":[{"id":"a","text":"Company-Wide"},{"id":"b","text":"Selected Teams"},{"id":"c","text":"Team Leads Only","isCorrect":true},{"id":"d","text":"Individual Team"}],"explanation":"Team Leads Only targets only users in a leadership role (Manager or Admin), company-wide — not every member. It does not use Target Teams (no team picker appears for it). Selected Teams would instead reach every member of the teams you pick."},{"id":"ann3","text":"When does the Target Teams multi-select appear in the Send Announcement dialog?","options":[{"id":"a","text":"Always — every announcement must target at least one team"},{"id":"b","text":"Only when Scope is Selected Teams or Individual Team (the team-based scopes)","isCorrect":true},{"id":"c","text":"Only when Severity is set to Critical"},{"id":"d","text":"Only after you pick a template"}],"explanation":"Target Teams appears only for the team-based scopes — Selected Teams and Individual Team — so you can define which teams receive the announcement. For Company-Wide and Team Leads Only there is no team selection (Team Leads Only always goes to all managers/admins company-wide)."},{"id":"ann4","text":"How do you see exactly who has acknowledged an announcement you sent?","options":[{"id":"a","text":"Click the announcement's row (or its eye icon) to open the Acknowledgments roster dialog","isCorrect":true},{"id":"b","text":"Hover over the Acks number to see a tooltip list"},{"id":"c","text":"Export the announcement to CSV"},{"id":"d","text":"Check the Notifications panel for read receipts"}],"explanation":"Clicking a row (or the visibility/eye icon on it) opens the Acknowledgments dialog. It shows a count of how many acknowledged, whether acknowledgment was required, and each person's name with the date/time they acknowledged."},{"id":"ann5","text":"What does turning on 'Require Acknowledgment' actually do?","options":[{"id":"a","text":"It changes the announcement's audience to managers only"},{"id":"b","text":"It makes recipients click to acknowledge, so the Acks count and roster become meaningful tracking","isCorrect":true},{"id":"c","text":"It automatically deletes the announcement once everyone reads it"},{"id":"d","text":"It changes the severity chip to red"}],"explanation":"Require Acknowledgment makes recipients explicitly acknowledge the announcement. That is what populates the Acks count and the acknowledgment roster, letting you confirm a notice reached the people who needed to see it. Without it, people simply read the banner."},{"id":"ann6","text":"You send the same maintenance-window notice every month. What is the best way to speed that up?","options":[{"id":"a","text":"Copy and paste the text from an old chat message each time"},{"id":"b","text":"Create a Template on the Templates tab, then pick it in the Template dropdown when sending to prefill the fields","isCorrect":true},{"id":"c","text":"Edit a previously sent announcement and resend it"},{"id":"d","text":"There is no reuse — you must retype it every time"}],"explanation":"Save a reusable Template (name, default content, default severity, default scope, default acknowledgment setting) on the Templates tab. When sending, choosing that template in the Template dropdown prefills Content, Severity, Scope, and the acknowledgment toggle — you can edit any field before sending."},{"id":"ann7","text":"What does the Severity setting (Info / Warning / Critical) control?","options":[{"id":"a","text":"Who receives the announcement"},{"id":"b","text":"The urgency signal and the color of the chip — it does not change the audience","isCorrect":true},{"id":"c","text":"Whether the announcement expires"},{"id":"d","text":"Whether acknowledgment is required"}],"explanation":"Severity is a signal of urgency and what color the chip is (Info blue, Warning amber, Critical red). It is independent of audience (that's Scope), expiry (Expires At), and acknowledgment (Require Acknowledgment)."},{"id":"ann8","text":"A teammate sends an announcement while you are looking at the sent-announcements list. What happens?","options":[{"id":"a","text":"Nothing until you manually refresh the page"},{"id":"b","text":"It appears at the top of the list in real time","isCorrect":true},{"id":"c","text":"You are logged out and must sign back in to see it"},{"id":"d","text":"It only shows up after the announcement expires"}],"explanation":"The sent-announcements list updates in real time. A new announcement — including one sent by a colleague while you are viewing the list — is pushed to the top without a manual refresh."},{"id":"ann9","text":"You delete a template from the Templates tab. What happens to announcements already sent from it?","options":[{"id":"a","text":"They are retracted from everyone who received them"},{"id":"b","text":"They are unaffected — deleting a template does not touch announcements already sent","isCorrect":true},{"id":"c","text":"Their acknowledgment rosters are cleared"},{"id":"d","text":"They lose their severity and become Info"}],"explanation":"Deleting a template only removes the reusable preset. Announcements already sent from it remain in the sent list with their rosters and severity intact — the template is just a starting point for composing, not a live link to past sends."},{"id":"ann10","text":"Which roles can create and delete announcement templates?","options":[{"id":"a","text":"Any user"},{"id":"b","text":"Admin only","isCorrect":true},{"id":"c","text":"Admin or Manager"},{"id":"d","text":"Team leads"}],"explanation":"Sending announcements and viewing the sent list / acknowledgments is open to Admin or Manager, but creating and deleting templates is Admin-only."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Announcements admin — Advanced Reference",
            Slug = "announcements-reference",
            Summary = "Edge-case and power-user reference for Announcements admin: API-only Retract/Update affordances, system-generated announcements, the parked Department scope, field-length limits and chip semantics, and the SignalR real-time push into the admin list.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/admin/announcements"]""",
            Tags = """["announcements","reference","advanced"]""",
            ContentJson = """{"body":"## Editing or Taking Back a Sent Announcement\n\nSome things you can do with an announcement are not offered in the panel yet.\n\n- **Taking one back.** A sent announcement can be removed, but the sent list has no button for it — the only thing you can do on a row is click the eye icon to see who confirmed. Taking back a sent announcement is not something the panel offers today.\n- **Editing one.** A sent announcement's title, message, and urgency can be changed, but again there is no way to do it from the panel. From your point of view, a sent announcement can't be edited here.\n- **Templates can be deleted here.** The trash icon on a template's row does delete it, after you confirm. That is the one delete the panel offers, and it does not touch announcements already sent from the template.\n\nBottom line: the list of sent announcements is view-only in the panel (you can only see who confirmed); editing or taking one back is not available here yet.\n\n## Announcements Sent by the System\n\nNot every announcement comes from a person using the send window. Some are created automatically by the system — for example, a scheduled job that posts a routine notice.\n\n- These automatic notices show **\"System\"** as the sender instead of a person's name.\n- They appear in the sent list right alongside the ones people write by hand.\n- Their urgency, audience, and confirmation behavior all work exactly the same as a hand-written announcement.\n\n## Department Audience (Planned, Not Yet Available)\n\nSending to a single department is planned but not turned on yet.\n\n- The send window's audience choices are only **Company-Wide, Selected Teams, Individual Team, and Team Leads Only** — there is no Department choice.\n- Until departments exist in the app, a department-targeted announcement would simply reach the whole company.\n\nIn short: sending to a department is groundwork for the future — there are no departments to send to yet, so the choice is hidden and anything department-targeted goes company-wide.\n\n## Length Limits & Label Colors\n\nThe exact limits and what the colored labels mean.\n\n- **Title** — required, up to **200** characters. A template's **name** has the same 200-character limit.\n- **Content** — required, up to **5,000** characters. A template's **message** has the same 5,000-character limit.\n- **Urgency label** — Info is blue, Warning is amber, Critical is red. Urgency is only a signal and a color; it does not change who gets the announcement or make people confirm it.\n- **Confirm-required label** (Templates list) — shows a highlighted **Yes** or a plain **No**, matching whether the template asks people to confirm.\n- **Acks count** — how many people confirmed. It only means something when confirmation was required; otherwise it just counts anyone who chose to confirm.\n\n## How New Announcements Appear Instantly\n\nNew announcements show up in the list (and pop up for recipients) without anyone refreshing the page.\n\n- **Live delivery.** The moment you send, the announcement is pushed to the right people: to everyone for a company-wide one, to the chosen members for a team one, and to all managers and admins for a team-leads one.\n- **Live list.** The panel adds each new announcement to the top of the list as it arrives, so a colleague's send and your own each show up once, right away, without reloading.\n- **When the feature is turned off.** If announcements are turned off for your install, the panel is hidden and nothing is fetched.","sections":[]}"""
        });

        Log.Information("Seeded Announcements admin training modules");
    }
